{"action":"write","content":"const si = require('systeminformation');

// Configuration
const HISTORY_LENGTH = 150; // ~5 minutes at 2-second intervals
const POLL_INTERVAL_MS = 2000;

// Rolling history buffer
const history = [];

/**
 * Collect current system stats using systeminformation.
 * Returns an object with CPU and memory data.
 */
async function collectStats() {
  const [cpuLoad, memData] = await Promise.all([
    si.currentLoad(),
    si.mem()
  ]);

  const cpu = {
    overallLoad: parseFloat(cpuLoad.currentLoad.toFixed(1)),
    coresLoad: cpuLoad.cpus.map(c => parseFloat(c.load.toFixed(1)))
  };

  const memory = {
    total: memData.total,
    used: memData.active,
    free: memData.free,
    percentage: parseFloat(((memData.active / memData.total) * 100).toFixed(1))
  };

  const timestamp = Date.now();

  // Add to rolling history
  history.push({
    timestamp,
    cpuOverall: cpu.overallLoad,
    memoryPercentage: memory.percentage
  });

  // Trim to max length
  if (history.length > HISTORY_LENGTH) {
    history.shift();
  }

  return {
    cpu,
    memory,
    history: [...history], // return a copy
    timestamp
  };
}

/**
 * Get the current stats without adding a new history point.
 * Useful for initial data push on client connect.
 */
function getLatestStats() {
  if (history.length === 0) {
    return null;
  }
  const last = history[history.length - 1];
  return {
    history: [...history],
    timestamp: last.timestamp
  };
}

module.exports = {
  collectStats,
  getLatestStats,
  POLL_INTERVAL_MS,
  HISTORY_LENGTH
};
","path":"monitor.js"}

