{"action":"write","content":"* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
  background: #0f172a;
  color: #e2e8f0;
  min-height: 100vh;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem 1rem;
}

header {
  text-align: center;
  margin-bottom: 2rem;
}

header h1 {
  font-size: 2.5rem;
  font-weight: 700;
  color: #38bdf8;
  margin-bottom: 0.5rem;
}

.subtitle {
  color: #94a3b8;
  font-size: 1.1rem;
}

/* Stats Grid */
.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.stat-card {
  background: #1e293b;
  border-radius: 12px;
  padding: 1.5rem;
  border: 1px solid #334155;
  transition: transform 0.2s, box-shadow 0.2s;
}

.stat-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.3);
}

.stat-card.wide {
  grid-column: 1 / -1;
}

.stat-card h2 {
  font-size: 0.875rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #94a3b8;
  margin-bottom: 1rem;
}

.stat-value {
  font-size: 2.5rem;
  font-weight: 700;
  color: #f8fafc;
  margin-bottom: 0.75rem;
}

.stat-bar {
  width: 100%;
  height: 8px;
  background: #334155;
  border-radius: 4px;
  overflow: hidden;
  margin-bottom: 0.5rem;
}

.stat-bar-fill {
  height: 100%;
  background: linear-gradient(90deg, #22d3ee, #38bdf8);
  border-radius: 4px;
  transition: width 0.5s ease;
  width: 0%;
}

.stat-detail {
  font-size: 0.875rem;
  color: #94a3b8;
}

/* Cores Grid */
.cores-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
  gap: 0.75rem;
}

.core-item {
  background: #334155;
  border-radius: 8px;
  padding: 0.75rem;
  text-align: center;
}

.core-label {
  font-size: 0.75rem;
  color: #94a3b8;
  margin-bottom: 0.25rem;
}

.core-value {
  font-size: 1.25rem;
  font-weight: 600;
  color: #f8fafc;
}

.core-bar {
  width: 100%;
  height: 4px;
  background: #475569;
  border-radius: 2px;
  overflow: hidden;
  margin-top: 0.5rem;
}

.core-bar-fill {
  height: 100%;
  background: #22d3ee;
  border-radius: 2px;
  transition: width 0.5s ease;
  width: 0%;
}

/* Charts Section */
.charts-section {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(400px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.chart-card {
  background: #1e293b;
  border-radius: 12px;
  padding: 1.5rem;
  border: 1px solid #334155;
}

.chart-card h2 {
  font-size: 1rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #94a3b8;
  margin-bottom: 1rem;
}

.chart-card canvas {
  max-height: 300px;
}

/* Footer */
footer {
  text-align: center;
  color: #64748b;
  font-size: 0.875rem;
  padding-top: 1rem;
  border-top: 1px solid #334155;
}

/* Responsive */
@media (max-width: 768px) {
  .charts-section {
    grid-template-columns: 1fr;
  }

  .stat-value {
    font-size: 2rem;
  }

  header h1 {
    font-size: 2rem;
  }
}
","path":"public/style.css"}

{"action":"write","content":"/**
 * System Monitor Dashboard Frontend
 * Connects via Socket.IO and updates charts/values in real time.
 */

// DOM Elements
const cpuOverallEl = document.getElementById('cpu-overall');
const cpuOverallBarEl = document.getElementById('cpu-overall-bar');
const memoryUsedEl = document.getElementById('memory-used');
const memoryBarEl = document.getElementById('memory-bar');
const memoryPercentEl = document.getElementById('memory-percent');
const coresGridEl = document.getElementById('cores-grid');

// Chart instances
let cpuChart = null;
let memoryChart = null;

/**
 * Format bytes to human-readable string.
 */
function formatBytes(bytes) {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
}

/**
 * Format a timestamp to HH:MM:SS.
 */
function formatTime(timestamp) {
  const d = new Date(timestamp);
  return d.toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });
}

/**
 * Initialize Chart.js charts.
 */
function initCharts() {
  const commonOptions = {
    responsive: true,
    maintainAspectRatio: false,
    animation: { duration: 0 },
    interaction: {
      mode: 'index',
      intersect: false
    },
    plugins: {
      legend: { display: false },
      tooltip: {
        backgroundColor: '#1e293b',
        titleColor: '#e2e8f0',
        bodyColor: '#e2e8f0',
        borderColor: '#334155',
        borderWidth: 1
      }
    },
    scales: {
      x: {
        grid: { color: '#334155' },
        ticks: { color: '#94a3b8', maxTicksLimit: 8 }
      },
      y: {
        min: 0,
        max: 100,
        grid: { color: '#334155' },
        ticks: { color: '#94a3b8', callback: (v) => v + '%' }
      }
    }
  };

  const cpuCtx = document.getElementById('cpu-chart').getContext('2d');
  cpuChart = new Chart(cpuCtx, {
    type: 'line',
    data: {
      labels: [],
      datasets: [{
        label: 'CPU %',
        data: [],
        borderColor: '#38bdf8',
        backgroundColor: 'rgba(56, 189, 248, 0.1)',
        borderWidth: 2,
        fill: true,
        tension: 0.3,
        pointRadius: 0,
        pointHoverRadius: 4
      }]
    },
    options: commonOptions
  });

  const memCtx = document.getElementById('memory-chart').getContext('2d');
  memoryChart = new Chart(memCtx, {
    type: 'line',
    data: {
      labels: [],
      datasets: [{
        label: 'Memory %',
        data: [],
        borderColor: '#a78bfa',
        backgroundColor: 'rgba(167, 139, 250, 0.1)',
        borderWidth: 2,
        fill: true,
        tension: 0.3,
        pointRadius: 0,
        pointHoverRadius: 4
      }]
    },
    options: commonOptions
  });
}

/**
 * Create or update the CPU cores grid.
 */
function updateCores(coresLoad) {
  // If first time, create all core elements
  if (coresGridEl.children.length !== coresLoad.length) {
    coresGridEl.innerHTML = '';
    coresLoad.forEach((load, index) => {
      const coreDiv = document.createElement('div');
      coreDiv.className = 'core-item';
      coreDiv.innerHTML = `
        <div class="core-label">Core ${index}</div>
        <div class="core-value" id="core-value-${index}">--%</div>
        <div class="core-bar">
          <div class="core-bar-fill" id="core-bar-${index}"></div>
        </div>
      `;
      coresGridEl.appendChild(coreDiv);
    });
  }

  // Update values
  coresLoad.forEach((load, index) => {
    const valueEl = document.getElementById(`core-value-${index}`);
    const barEl = document.getElementById(`core-bar-${index}`);
    if (valueEl) valueEl.textContent = load + '%';
    if (barEl) barEl.style.width = load + '%';
  });
}

/**
 * Update the dashboard with new stats data.
 */
function updateDashboard(stats) {
  const { cpu, memory, history } = stats;

  // Update CPU overall
  if (cpu) {
    cpuOverallEl.textContent = cpu.overallLoad + '%';
    cpuOverallBarEl.style.width = cpu.overallLoad + '%';
    updateCores(cpu.coresLoad);
  }

  // Update Memory
  if (memory) {
    memoryUsedEl.textContent = `${formatBytes(memory.used)} / ${formatBytes(memory.total)}`;
    memoryBarEl.style.width = memory.percentage + '%';
    memoryPercentEl.textContent = memory.percentage + '% used';
  }

  // Update charts
  if (history && history.length > 0) {
    const labels = history.map(h => formatTime(h.timestamp));
    const cpuData = history.map(h => h.cpuOverall);
    const memData = history.map(h => h.memoryPercentage);

    cpuChart.data.labels = labels;
    cpuChart.data.datasets[0].data = cpuData;
    cpuChart.update('none');

    memoryChart.data.labels = labels;
    memoryChart.data.datasets[0].data = memData;
    memoryChart.update('none');
  }
}

/**
 * Main entry point.
 */
function main() {
  initCharts();

  const socket = io();

  socket.on('connect', () => {
    console.log('Connected to server');
  });

  socket.on('disconnect', () => {
    console.log('Disconnected from server');
  });

  socket.on('stats', (stats) => {
    updateDashboard(stats);
  });
}

// Start when DOM is ready
document.addEventListener('DOMContentLoaded', main);
","path":"public/app.js"}

