Read file: public/app.js

/**
 * System Monitor Dashboard Frontend
 * Connects via Socket.IO and updates charts/values in real time.
 */

// DOM Elements
const cpuOverallEl = document.getElementById('cpu-overall');
const cpuOverallBarEl = document.getElementById('cpu-overall-bar');
const memoryUsedEl = document.getElementById('memory-used');
const memoryBarEl = document.getElementById('memory-bar');
const memoryPercentEl = document.getElementById('memory-percent');
const coresGridEl = document.getElementById('cores-grid');
const connectionStatusEl = document.getElementById('connection-status');
const statusTextEl = document.getElementById('status-text');
const cpuCardEl = document.getElementById('cpu-card');
const memoryCardEl = document.getElementById('memory-card');

// Chart instances
let cpuChart = null;
let memoryChart = null;

/**
 * Format bytes to human-readable string.
 */
function formatBytes(bytes) {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
}

/**
 * Format a timestamp to HH:MM:SS.
 */
function formatTime(timestamp) {
  const d = new Date(timestamp);
  return d.toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });
}

/**
 * Update the connection status badge.
 */
function updateConnectionStatus(state, text) {
  if (!connectionStatusEl || !statusTextEl) return;
  connectionStatusEl.className = 'connection-status ' + state;
  statusTextEl.textContent = text;
}

/**
 * Apply alert classes based on usage thresholds.
 * Warning: > 60%, Critical: > 80%
 */
function applyAlertLevel(element, value) {
  if (!element) return;
  element.classList.remove('warning', 'critical');
  if (value > 80) {
    element.classList.add('critical');
  } else if (value > 60) {
    element.classList.add('warning');
  }
}

/**
 * Initialize Chart.js charts.
 */
function initCharts() {
  const commonOptions = {
    responsive: true,
    maintainAspectRatio: false,
    animation: { duration: 0 },
    interaction: {
      mode: 'index',
      intersect: false
    },
    plugins: {
      legend: { display: false },
      tooltip: {
        backgroundColor: '#1e293b',
        titleColor: '#e2e8f0',
        bodyColor: '#e2e8f0',
        borderColor: '#334155',
        borderWidth: 1
      }
    },
    scales: {
      x: {
        grid: { color: '#334155' },
        ticks: { color: '#94a3b8', maxTicksLimit: 8 }
      },
      y: {
        min: 0,
        max: 100,
        grid: { color: '#334155' },
        ticks: { color: '#94a3b8', callback: (v) => v + '%' }
      }
    }
  };

  const cpuCtx = document.getElementById('cpu-chart').getContext('2d');
  cpuChart = new Chart(cpuCtx, {
    type: 'line',
    data: {
      labels: [],
      datasets: [{
        label: 'CPU %',
        data: [],
        borderColor: '#38bdf8',
        backgroundColor: 'rgba(56, 189, 248, 0.1)',
        borderWidth: 2,
        fill: true,
        tension: 0.3,
        pointRadius: 0,
        pointHoverRadius: 4
      }]
    },
    options: commonOptions
  });

  const memCtx = document.getElementById('memory-chart').getContext('2d');
  memoryChart = new Chart(memCtx, {
    type: 'line',
    data: {
      labels: [],
      datasets: [{
        label: 'Memory %',
        data: [],
        borderColor: '#a78bfa',
        backgroundColor: 'rgba(167, 139, 250, 0.1)',
        borderWidth: 2,
        fill: true,
        tension: 0.3,
        pointRadius: 0,
        pointHoverRadius: 4
      }]
    },
    options: commonOptions
  });
}

/**
 * Create or update the CPU cores grid.
 */
function updateCores(coresLoad) {
  // If first time, create all core elements
  if (coresGridEl.children.length !== coresLoad.length) {
    coresGridEl.innerHTML = '';
    coresLoad.forEach((load, index) => {
      const coreDiv = document.createElement('div');
      coreDiv.className = 'core-item';
      coreDiv.id = `core-item-${index}`;
      coreDiv.innerHTML = `
        <div class="core-label">Core ${index}</div>
        <div class="core-value" id="core-value-${index}">--%</div>
        <div class="core-bar">
          <div class="core-bar-fill" id="core-bar-${index}"></div>
        </div>
      `;
      coresGridEl.appendChild(coreDiv);
    });
  }

  // Update values and alert levels
  coresLoad.forEach((load, index) => {
    const valueEl = document.getElementById(`core-value-${index}`);
    const barEl = document.getElementById(`core-bar-${index}`);
    const itemEl = document.getElementById(`core-item-${index}`);
    if (valueEl) valueEl.textContent = load + '%';
    if (barEl) barEl.style.width = load + '%';
    applyAlertLevel(itemEl, load);
  });
}

/**
 * Update the dashboard with new stats data.
 */
function updateDashboard(stats) {
  const { cpu, memory, history } = stats;

  // Update CPU overall
  if (cpu) {
    cpuOverallEl.textContent = cpu.overallLoad + '%';
    cpuOverallBarEl.style.width = cpu.overallLoad + '%';
    applyAlertLevel(cpuCardEl, cpu.overallLoad);
    updateCores(cpu.coresLoad);
  }

  // Update Memory
  if (memory) {
    memoryUsedEl.textContent = `${formatBytes(memory.used)} / ${formatBytes(memory.total)}`;
    memoryBarEl.style.width = memory.percentage + '%';
    memoryPercentEl.textContent = memory.percentage + '% used';
    applyAlertLevel(memoryCardEl, memory.percentage);
  }

  // Update charts
  if (history && history.length > 0) {
    const labels = history.map(h => formatTime(h.timestamp));
    const cpuData = history.map(h => h.cpuOverall);
    const memData = history.map(h => h.memoryPercentage);

    cpuChart.data.labels = labels;
    cpuChart.data.datasets[0].data = cpuData;
    cpuChart.update('none');

    memoryChart.data.labels = labels;
    memoryChart.data.datasets[0].data = memData;
    memoryChart.update('none');
  }
}

/**
 * Main entry point.
 */
function main() {
  initCharts();

  const socket = io();

  socket.on('connect', () => {
    console.log('Connected to server');
    updateConnectionStatus('connected', 'Connected');
  });

  socket.on('disconnect', () => {
    console.log('Disconnected from server');
    updateConnectionStatus('disconnected', 'Disconnected');
  });

  socket.on('reconnecting', () => {
    console.log('Reconnecting to server');
    updateConnectionStatus('reconnecting', 'Reconnecting...');
  });

  socket.on('stats', (stats) => {
    updateDashboard(stats);
  });
}

// Start when DOM is ready
document.addEventListener('DOMContentLoaded', main);

