  height: 8px;
  background: rgba(255, 255, 255, 0.08);
  border-radius: 4px;
  overflow: hidden;
  margin-bottom: 0.5rem;
}

.stat-bar-fill {
  height: 100%;
  background: linear-gradient(90deg, #22d3ee, #38bdf8);
  border-radius: 4px;
  transition: width 0.6s cubic-bezier(0.4, 0, 0.2, 1), background 0.4s ease;
  width: 0%;
  box-shadow: 0 0 8px rgba(56, 189, 248, 0.3);
}

.stat-detail {
  font-size: 0.875rem;
  color: #94a3b8;
}

/* Alert Thresholds */
.stat-card.warning {
  border-color: rgba(234, 179, 8, 0.4);
  box-shadow: 0 0 20px rgba(234, 179, 8, 0.1), 0 4px 24px rgba(0, 0, 0, 0.2);
}
.stat-card.warning .stat-bar-fill {
  background: linear-gradient(90deg, #eab308, #f59e0b);
  box-shadow: 0 0 8px rgba(234, 179, 8, 0.3);
}

.stat-card.critical {
  border-color: rgba(239, 68, 68, 0.4);
  box-shadow: 0 0 24px rgba(239, 68, 68, 0.15), 0 4px 24px rgba(0, 0, 0, 0.2);
  animation: criticalPulse 2s ease-in-out infinite;
}
.stat-card.critical .stat-bar-fill {
  background: linear-gradient(90deg, #ef4444, #f97316);
  box-shadow: 0 0 8px rgba(239, 68, 68, 0.3);
}
.stat-card.critical .stat-value {
  color: #ef4444;
}

@keyframes criticalPulse {
  0%, 100% { box-shadow: 0 0 24px rgba(239, 68, 68, 0.15), 0 4px 24px rgba(0, 0, 0, 0.2); }
  50% { box-shadow: 0 0 32px rgba(239, 68, 68, 0.25), 0 4px 24px rgba(0, 0, 0, 0.2); }
}

/* Cores Grid */
.cores-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
  gap: 0.75rem;
}

.core-item {
  background: rgba(51, 65, 85, 0.5);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  border-radius: 10px;
  padding: 0.75rem;
  text-align: center;
  border: 1px solid rgba(255, 255, 255, 0.05);
  transition: background 0.3s ease, border-color 0.3s ease, transform 0.2s ease;
}

.core-item:hover {
  background: rgba(51, 65, 85, 0.7);
  border-color: rgba(56, 189, 248, 0.15);
  transform: translateY(-2px);
}

.core-label {
  font-size: 0.75rem;
  color: #94a3b8;
  margin-bottom: 0.25rem;
}

.core-value {
  font-size: 1.25rem;
  font-weight: 600;
  color: #f8fafc;
  transition: color 0.3s ease;
}

.core-bar {
  width: 100%;
  height: 4px;
  background: rgba(255, 255, 255, 0.08);
  border-radius: 2px;
  overflow: hidden;
  margin-top: 0.5rem;
}

.core-bar-fill {
  height: 100%;
  background: #22d3ee;
  border-radius: 2px;
  transition: width 0.5s ease, background 0.3s ease;
  width: 0%;
}

.core-item.warning .core-bar-fill {
  background: #eab308;
}
.core-item.critical .core-bar-fill {
  background: #ef4444;
}
.core-item.critical .core-value {
  color: #ef4444;
}

/* Charts Section */
.charts-section {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(400px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.chart-card canvas {
  max-height: 300px;
}

/* Footer */
footer {
  text-align: center;
  color: #64748b;
  font-size: 0.875rem;
  padding-top: 1.5rem;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.last-updated {
  margin-top: 0.5rem;
  font-size: 0.75rem;
  color: #475569;
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.02em;
  transition: color 0.3s ease;
}

.last-updated.recent {
  color: #22c55e;
}

/* Custom Scrollbar */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: rgba(15, 23, 42, 0.5);
}

::-webkit-scrollbar-thumb {
  background: rgba(100, 116, 139, 0.5);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(100, 116, 139, 0.7);
}

/* Responsive */
@media (max-width: 768px) {
