const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');
const path = require('path');
const { collectStats, getLatestStats, POLL_INTERVAL_MS } = require('./monitor');

const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer, {
  cors: {
    origin: '*'
  }
});

const PORT = process.env.PORT || 3000;

// Serve static frontend files
app.use(express.static(path.join(__dirname, 'public')));

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

// Socket.IO connection handling
io.on('connection', (socket) => {
  console.log('Client connected:', socket.id);

  // Send existing history to the new client immediately
  const latest = getLatestStats();
  if (latest) {
    socket.emit('stats', latest);
  }

  socket.on('disconnect', () => {
    console.log('Client disconnected:', socket.id);
  });
});

// Start polling system stats and broadcast to all clients
async function startPolling() {
  try {
    const stats = await collectStats();
    io.emit('stats', stats);
  } catch (err) {
    console.error('Error collecting stats:', err.message);
  }
}

// Run immediately once, then on interval
startPolling();
const pollInterval = setInterval(startPolling, POLL_INTERVAL_MS);

// Graceful shutdown
process.on('SIGINT', () => {
  console.log('\nShutting down server...');
  clearInterval(pollInterval);
  io.close();
  httpServer.close(() => {
    process.exit(0);
  });
});

httpServer.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});
